const strategy = $input.item.json.output || {};
const lead = $('Get Stage 2 Leads').item.json;

// Parse pain points safely
let painPoints = [];
try {
  painPoints = typeof lead.pain_points === 'string'
    ? JSON.parse(lead.pain_points)
    : lead.pain_points || [];
} catch(e) { painPoints = []; }

// Score calculation
let finalScore = 0;

// Contact quality (20pts)
if (lead.email) finalScore += 15;
if (lead.domain) finalScore += 5;

// Business intelligence (25pts)
if (lead.company_size === 'medium' || lead.company_size === 'large') finalScore += 15;
else if (lead.company_size === 'small') finalScore += 10;
if (painPoints.length >= 3) finalScore += 10;

// Business health (20pts)
if (lead.rating >= 4.5) finalScore += 12;
else if (lead.rating >= 4.0) finalScore += 8;
else if (lead.rating >= 3.5) finalScore += 4;
if (lead.review_count > 500) finalScore += 8;
else if (lead.review_count > 100) finalScore += 5;
else if (lead.review_count > 20) finalScore += 3;

// Personalization quality (20pts)
if (lead.personalization_hook && lead.personalization_hook.length > 20) finalScore += 10;
if (strategy.email_subject_line) finalScore += 10;

// Response rate (15pts)
const responseRate = parseInt(strategy.estimated_response_rate) || 0;
if (responseRate >= 25) finalScore += 15;
else if (responseRate >= 15) finalScore += 10;
else if (responseRate >= 10) finalScore += 5;

// Priority
let priority = 'cold';
if (finalScore >= 75) priority = 'hot';
else if (finalScore >= 55) priority = 'warm';

// Engagement
let engagement = 'not_ready';
if (lead.email && finalScore >= 70) engagement = 'ready';
else if (finalScore >= 50) engagement = 'needs_nurturing';

return {
  lead_id: lead.id,
  company_name: lead.company_name,
  email_should_use: lead.email ? true : false,
  email_subject_line: strategy.email_subject_line || null,
  email_opening: strategy.opening_sentence || null,
  email_body_template: strategy.email_body || null,
  email_follow_up_day_3: strategy.follow_up_day_3 || null,
  email_follow_up_day_7: strategy.follow_up_day_7 || null,
  linkedin_should_use: lead.company_linkedin_url ? true : false,
  linkedin_connection_note: strategy.linkedin_connection_note || null,
  linkedin_first_message: strategy.linkedin_first_message || null,
  linkedin_approach: strategy.linkedin_approach || 'connection_request',
  sms_should_use: lead.phone ? true : false,
  sms_message: strategy.sms_message || null,
  sms_timing: strategy.sms_timing || 'After email if no response in 3 days',
  whatsapp_should_use: lead.phone ? true : false,
  whatsapp_message: strategy.whatsapp_message || null,
  whatsapp_timing: strategy.whatsapp_timing || 'After SMS if no response in 5 days',
  primary_channel: strategy.channel_strategy?.primary_channel || (lead.email ? 'email' : 'sms'),
  lead_score: Math.min(100, finalScore),
  priority: priority,
  engagement_readiness: engagement
};
